import java.io.ByteArrayInputStream;
import java.io.ObjectInputStream;
import java.util.Base64;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String serializedData = "rO0ABXNyACVqYXZhLmxhbmcuU3RyaW5nAAAAAAAAAAICAAB4cAAAAANzcQB+AAQ=";
        byte[] serializedBytes = Base64.getDecoder().decode(serializedData);

        try (ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(serializedBytes))) {
            Object obj = ois.readObject();
            System.out.println("Deserialized object: " + obj);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

